defmodule BlogWeb.PostView do
  use BlogWeb, :view
end

defmodule BlogWeb.PostLive do
  use Phoenix.LiveView

  def render(assigns) do
    ~L"""
    <div class="post">
      <h1><%= @post.title %></h1>
      <div class="post-content">
        <%= raw @post.content %>
      </div>
    </div>
    """
  end

  def mount(_params, _session, socket) do
    {:ok, assign(socket, :post, get_post())}
  end

  defp get_post do
    %{
      title: "Sample Post",
      content: "<p>This is <strong>rich</strong> HTML content from user.</p><ul><li>Item 1</li><li>Item 2</li></ul>"
    }
  end
end